func_src_after:
#include <string>
#include <fstream>
#include <filesystem>
#include <stdexcept>

/* SECURE: canonicalize path and verify it stays within base_dir */
std::ifstream open_user_file(const std::string &base_dir,
                              const std::string &user_input) {
  std::filesystem::path base = std::filesystem::canonical(base_dir);
  std::filesystem::path full = std::filesystem::weakly_canonical(base / user_input);
  /* Ensure resolved path is still inside base */
  auto [base_end, _] = std::mismatch(base.begin(), base.end(), full.begin());
  if (base_end != base.end()) {
    throw std::runtime_error("Path traversal detected");
  }
  return std::ifstream(full);
}

