func_src_after:
#include <string>
#include <fstream>
#include <stdexcept>

/* SECURE: reject filenames containing / or .. sequences */
std::string read_config_file(const std::string &config_dir,
                              const std::string &filename) {
  if (filename.find('/') != std::string::npos  ||
      filename.find('\') != std::string::npos ||
      filename.find("..") != std::string::npos) {
    throw std::runtime_error("Invalid filename");
  }
  std::string path = config_dir + "/" + filename;
  std::ifstream f(path);
  return std::string(std::istreambuf_iterator<char>(f),
                     std::istreambuf_iterator<char>());
}
